interface ScheduleItem {
  time: string;
  title: string;
  desc: string;
  icon: React.ReactNode;
  travelTime?: string;
  mapQuery?: string;
  mapUrl?: string; // 직접적인 구글 맵 링크
  websiteUrl?: string;
  tags?: string[];
  alt?: ScheduleAlt;
}

interface DayItinerary {
  id: string;
  title: string;
  date: string;
  schedules: ScheduleItem[];
}

